SELECT id, analy_instrument_code, analy_instrument_purpose, analy_instrument_dept, analy_instrument_type, analy_instrument_big, analy_instrument_status, analy_instrument_plant, analy_instrument_unit, analy_instrument_monitor, analy_instrument_lock, analy_instrument_link_val, analy_instrument_alarm_val, analy_instrument_name, analy_instrument_process, analy_instrument_op_temp, analy_instrument_op_press, analy_instrument_range, analy_instrument_meas_unit, analy_instrument_set, analy_instrument_circuit, analy_instrument_supplier, analy_instrument_prod_date, analy_instrument_use_date, analy_instrument_guarantee_date, analy_instrument_maintain_flag, analy_instrument_lube_period, analy_instrument_lube_date, analy_instrument_voltage, analy_instrument_explosion, analy_instrument_protection, analy_instrument_manufacturer, analy_instrument_spec, analy_instrument_calib_date FROM analy_instrument
AND analy_instrument_code LIKE CONCAT('%', #{queryParams.analyInstrumentCode}, '%')
AND analy_instrument_type LIKE CONCAT('%', #{queryParams.analyInstrumentType}, '%')
AND analy_instrument_big LIKE CONCAT('%', #{queryParams.analyInstrumentBig}, '%')
AND analy_instrument_status = #{queryParams.analyInstrumentStatus}
AND analy_instrument_monitor = #{queryParams.analyInstrumentMonitor}
AND analy_instrument_lock = #{queryParams.analyInstrumentLock}

